    ],
  },
  {
    name: 'Team',
    price: '$30',
    period: '/month',
    badge: 'Study groups',
    current: false,
    features: [
      'Everything in Pro',
      'Up to 5 students',
      '5,000 messages/month',
      'Shared agents',
      'Group analytics',
