import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Eye, EyeOff, Copy, Trash2, Plus, Check, Brain, Smartphone, MessageCircle, ExternalLink, AlertCircle, Menu, ChevronRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';
import { Switch } from '@/components/ui/switch';
import { Sheet, SheetContent } from '@/components/ui/sheet';
import AppHeader from '@/components/layout/AppHeader';
import { toast } from 'sonner';
import { Toaster } from '@/components/ui/sonner';
import { mockAgents } from '@/lib/mock-data';
import { cn } from '@/lib/utils';
import { formatDistanceToNow } from 'date-fns';

function Section({ title, desc, children }: { title: string; desc?: string; children: React.ReactNode }) {
  return (
    <div className="space-y-4">
      <div>
        <h3 className="text-sm font-medium">{title}</h3>
        {desc && <p className="text-xs text-muted-foreground mt-0.5">{desc}</p>}
      </div>
      {children}
    </div>
  );
}

function ProfileSettings() {
  const [saved, setSaved] = useState(false);
  const handleSave = () => { setSaved(true); toast('Profile saved'); setTimeout(() => setSaved(false), 2500); };
  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }} className="space-y-8 max-w-lg">
      <Section title="Profile">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 rounded-full bg-secondary border border-border flex items-center justify-center text-xl font-medium shadow-elevation-sm">U</div>
          <div>
            <Button variant="outline" size="sm" className="text-xs h-8 shadow-elevation-sm">Change avatar</Button>
            <p className="text-[11px] text-muted-foreground mt-1.5">JPG, PNG or GIF. Max 2MB.</p>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1.5"><Label className="text-xs">First name</Label><Input defaultValue="Alex" className="h-9 text-sm shadow-elevation-sm" /></div>
          <div className="space-y-1.5"><Label className="text-xs">Last name</Label><Input defaultValue="Student" className="h-9 text-sm shadow-elevation-sm" /></div>
        </div>
        <div className="space-y-1.5"><Label className="text-xs">Email</Label><Input defaultValue="alex@university.edu" className="h-9 text-sm shadow-elevation-sm" /></div>
        <div className="space-y-1.5">
          <Label className="text-xs">University / Institution</Label>
          <Input defaultValue="State University" className="h-9 text-sm shadow-elevation-sm" />
        </div>
      </Section>
      <Separator />
      <Section title="Notifications" desc="Control when and how WebCon contacts you.">
        <div className="space-y-4">
          {[
            { label: 'Study reminders', desc: 'Get reminders to check in with your agents' },
            { label: 'Session summaries', desc: 'Receive weekly summaries of your study sessions' },
            { label: 'New feature updates', desc: 'Be first to know about new platform features' },
          ].map(item => (
            <div key={item.label} className="flex items-center justify-between py-1">
              <div><p className="text-sm">{item.label}</p><p className="text-xs text-muted-foreground mt-0.5">{item.desc}</p></div>
              <Switch defaultChecked={item.label !== 'New feature updates'} />
            </div>
          ))}
        </div>
      </Section>
      <Button size="sm" className="h-9 px-5 text-xs shadow-elevation-sm" onClick={handleSave}>
        {saved ? <><Check className="h-3.5 w-3.5 mr-1.5" />Saved</> : 'Save changes'}
      </Button>
    </motion.div>
  );
}

function AgentsSettings() {
  const [agents, setAgents] = useState(mockAgents);

  const handleDelete = (id: string) => {
    setAgents(prev => prev.filter(a => a.id !== id));
    toast('Agent deleted');
  };

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }} className="max-w-lg space-y-6">
      <Section title="Your agents" desc="Manage the AI agents you've created for each course.">
        <div className="space-y-3">
          <AnimatePresence>
            {agents.map(agent => (
              <motion.div
                key={agent.id}
                layout
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0, marginBottom: 0 }}
                transition={{ duration: 0.25 }}
                className="border border-border rounded-2xl p-4 bg-card shadow-elevation-sm"
              >
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-9 h-9 rounded-xl bg-secondary border border-border flex items-center justify-center shadow-elevation-sm">
                      <Brain className="h-4 w-4 text-muted-foreground" strokeWidth={1.5} />
                    </div>
                    <div>
                      <p className="text-sm font-medium">{agent.name}</p>
                      <p className="text-xs text-muted-foreground">{agent.subject} · {agent.conversations} conversations</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Button variant="outline" size="sm" className="h-7 text-xs shadow-elevation-sm">Edit</Button>
                    <Button variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-destructive transition-colors" onClick={() => handleDelete(agent.id)}>
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
                {agent.connected.length > 0 && (
                  <div className="flex items-center gap-1.5 mt-3 pt-3 border-t border-border">
                    <Smartphone className="h-3 w-3 text-muted-foreground" />
                    <span className="text-[11px] text-muted-foreground">Connected to </span>
                    {agent.connected.map(p => (
                      <span key={p} className="text-[11px] px-1.5 py-0.5 rounded-full border border-border bg-secondary text-muted-foreground capitalize">{p}</span>
                    ))}
                  </div>
                )}
                <p className="text-[11px] text-muted-foreground mt-2">Last active {formatDistanceToNow(agent.lastActive, { addSuffix: true })}</p>
              </motion.div>
            ))}
          </AnimatePresence>
          {agents.length === 0 && (
            <div className="border border-border rounded-2xl p-8 text-center">
              <Brain className="h-8 w-8 text-muted-foreground/40 mx-auto mb-3" strokeWidth={1} />
              <p className="text-sm text-muted-foreground">No agents yet</p>
              <p className="text-xs text-muted-foreground/60 mt-1">Create your first agent from the dashboard.</p>
            </div>
          )}
        </div>
      </Section>
      <Section title="Agent preferences" desc="Default settings applied when creating new agents.">
        <div className="space-y-3">
          <div className="space-y-1.5">
            <Label className="text-xs">Default study level</Label>
            <select className="w-full h-9 rounded-lg border border-border bg-background px-3 text-sm text-foreground focus:outline-none focus:border-foreground/30 transition-colors shadow-elevation-sm">
              <option>Undergraduate</option>
              <option>High School</option>
              <option>Graduate</option>
              <option>Self-study</option>
            </select>
          </div>
          <div className="flex items-center justify-between py-1">
            <div><p className="text-sm">Save conversation history</p><p className="text-xs text-muted-foreground mt-0.5">Keep all chats for review</p></div>
            <Switch defaultChecked />
          </div>
        </div>
      </Section>
    </motion.div>
  );
}

function IntegrationsSettings() {
  const [whatsappStep, setWhatsappStep] = useState<'idle' | 'connecting' | 'connected'>('idle');
  const [telegramStep, setTelegramStep] = useState<'idle' | 'connecting' | 'connected'>('connected');

  const connectWhatsApp = () => {
    setWhatsappStep('connecting');
    setTimeout(() => { setWhatsappStep('connected'); toast('WhatsApp connected successfully'); }, 2000);
  };

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }} className="max-w-lg space-y-6">
      <Section title="Messaging platforms" desc="Connect your agents to your preferred messaging apps.">
        <div className="space-y-3">
          {/* WhatsApp */}
          <div className="border border-border rounded-2xl p-5 bg-card shadow-elevation-sm">
            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-xl bg-secondary border border-border flex items-center justify-center shrink-0 shadow-elevation-sm">
                <MessageCircle className="h-5 w-5 text-muted-foreground" strokeWidth={1.5} />
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between mb-1">
                  <p className="text-sm font-medium">WhatsApp</p>
                  {whatsappStep === 'connected' && (
                    <span className="text-[11px] px-2 py-0.5 rounded-full border border-border bg-secondary text-muted-foreground">Connected</span>
                  )}
                </div>
                <p className="text-xs text-muted-foreground mb-4 leading-relaxed">
                  Ask your agents questions directly from WhatsApp. No app switching — answers come right to your chat.
                </p>
                <AnimatePresence mode="wait">
                  {whatsappStep === 'idle' && (
                    <motion.div key="idle" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                      <Button size="sm" variant="outline" className="h-8 text-xs shadow-elevation-sm" onClick={connectWhatsApp}>
                        Connect WhatsApp
                      </Button>
                    </motion.div>
                  )}
                  {whatsappStep === 'connecting' && (
                    <motion.div key="connecting" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="space-y-3">
                      <div className="p-4 rounded-xl border border-border bg-secondary/40 text-center">
                        <div className="w-24 h-24 bg-secondary border border-border rounded-xl mx-auto mb-3 flex items-center justify-center">
                          <div className="grid grid-cols-4 gap-0.5">
                            {Array.from({ length: 16 }).map((_, i) => (
                              <div key={i} className={`w-2 h-2 rounded-sm ${Math.random() > 0.5 ? 'bg-foreground' : 'bg-transparent'}`} />
                            ))}
                          </div>
                        </div>
                        <p className="text-xs text-muted-foreground">Scan with WhatsApp</p>
                        <p className="text-[11px] text-muted-foreground/60 mt-1">Open WhatsApp → Settings → Linked Devices</p>
                      </div>
                    </motion.div>
                  )}
                  {whatsappStep === 'connected' && (
                    <motion.div key="connected" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="flex items-center gap-2">
                      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                        <Check className="h-3.5 w-3.5" />
                        <span>All agents accessible on WhatsApp</span>
                      </div>
                      <button onClick={() => setWhatsappStep('idle')} className="text-xs text-muted-foreground hover:text-foreground transition-colors ml-auto">Disconnect</button>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          </div>

          {/* Telegram */}
          <div className="border border-border rounded-2xl p-5 bg-card shadow-elevation-sm">
            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-xl bg-secondary border border-border flex items-center justify-center shrink-0 shadow-elevation-sm">
                <Smartphone className="h-5 w-5 text-muted-foreground" strokeWidth={1.5} />
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between mb-1">
                  <p className="text-sm font-medium">Telegram</p>
                  {telegramStep === 'connected' && (
                    <span className="text-[11px] px-2 py-0.5 rounded-full border border-border bg-secondary text-muted-foreground">Connected</span>
                  )}
                </div>
                <p className="text-xs text-muted-foreground mb-4 leading-relaxed">
                  Get study help through a dedicated Telegram bot. Your agent arrives as a chat in your existing conversations.
                </p>
                {telegramStep === 'connected' ? (
                  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex items-center gap-2">
                    <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                      <Check className="h-3.5 w-3.5" />
                      <span>Bot active · @webcon_study_bot</span>
                    </div>
                    <button onClick={() => setTelegramStep('idle')} className="text-xs text-muted-foreground hover:text-foreground transition-colors ml-auto">Disconnect</button>
                  </motion.div>
                ) : (
                  <Button size="sm" variant="outline" className="h-8 text-xs shadow-elevation-sm" onClick={() => { setTelegramStep('connected'); toast('Telegram connected'); }}>
                    Connect Telegram
                  </Button>
                )}
              </div>
            </div>
          </div>
        </div>
      </Section>

      <Section title="Webhook" desc="Advanced: send agent responses to your own endpoint.">
        <div className="border border-border rounded-2xl p-4 bg-card shadow-elevation-sm">
          <div className="flex items-center gap-2 mb-3">
            <AlertCircle className="h-3.5 w-3.5 text-muted-foreground" />
            <span className="text-xs text-muted-foreground">For developers only</span>
            <a href="#" className="text-xs text-muted-foreground underline ml-auto flex items-center gap-1">Docs <ExternalLink className="h-3 w-3" /></a>
          </div>
          <div className="flex gap-2">
            <Input placeholder="https://your-server.com/webhook" className="h-9 text-sm shadow-elevation-sm flex-1" />
            <Button variant="outline" size="sm" className="h-9 text-xs shadow-elevation-sm shrink-0">Save</Button>
          </div>
        </div>
      </Section>
    </motion.div>
  );
}

function BillingSettings() {
  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }} className="max-w-lg space-y-6">
      <div className="border border-border rounded-2xl p-5 bg-card shadow-elevation-sm">
        <div className="flex items-start justify-between mb-5">
          <div>
            <p className="text-sm font-medium">Free plan</p>
            <p className="text-xs text-muted-foreground mt-1">Perfect for getting started</p>
          </div>
          <Button size="sm" className="h-8 text-xs shadow-elevation-sm">Upgrade to Pro</Button>
        </div>
        <div className="space-y-3">
          {[
            { label: 'Agents', used: 4, total: 5 },
            { label: 'AI messages this month', used: 67, total: 100 },
            { label: 'Platform connections', used: 2, total: 2 },
          ].map(item => (
            <div key={item.label}>
              <div className="flex items-center justify-between text-xs mb-1.5">
                <span className="text-muted-foreground">{item.label}</span>
                <span className={cn(item.used / item.total > 0.8 ? 'text-foreground font-medium' : '')}>{item.used} / {item.total}</span>
              </div>
              <div className="h-1.5 rounded-full bg-secondary border border-border overflow-hidden">
                <motion.div
                  className="h-full rounded-full bg-foreground"
                  initial={{ width: 0 }}
                  animate={{ width: `${(item.used / item.total) * 100}%` }}
                  transition={{ duration: 0.6, delay: 0.2, ease: [0.22, 1, 0.36, 1] }}
                />
              </div>
            </div>
          ))}
        </div>
      </div>

      <div>
        <p className="text-sm font-medium mb-4">Plans</p>
        <div className="grid grid-cols-2 gap-3">
          {[
            { name: 'Pro', price: '$12/mo', badge: 'Most popular', features: ['Unlimited agents', '1,000 messages/mo', 'WhatsApp + Telegram', 'Priority support', 'Study analytics'] },
            { name: 'Team', price: '$30/mo', badge: 'For study groups', features: ['Everything in Pro', 'Up to 5 students', '5,000 messages/mo', 'Shared agents', 'Admin controls'] },
          ].map((plan, i) => (
            <motion.div
              key={plan.name}
              whileHover={{ y: -2 }}
              transition={{ duration: 0.15 }}
              className="border border-border rounded-2xl p-5 bg-card shadow-elevation-sm hover:shadow-elevation-md transition-shadow"
            >
              <div className="flex items-start justify-between mb-1">
                <p className="text-sm font-medium">{plan.name}</p>
                <span className="text-[10px] px-1.5 py-0.5 rounded-full border border-border bg-secondary text-muted-foreground">{plan.badge}</span>
              </div>
              <p className="text-2xl font-semibold tracking-tight mt-1 mb-4">{plan.price}</p>
              <ul className="space-y-2 mb-5">
                {plan.features.map(f => (
                  <li key={f} className="text-xs text-muted-foreground flex items-center gap-2">
                    <Check className="h-3 w-3 text-foreground/60 shrink-0" />{f}
                  </li>
                ))}
              </ul>
              <Button size="sm" variant={i === 0 ? 'default' : 'outline'} className="w-full h-8 text-xs shadow-elevation-sm">
                Choose {plan.name}
              </Button>
            </motion.div>
          ))}
        </div>
      </div>
    </motion.div>
  );
}

const NAV_ITEMS = [
  { value: 'profile',      label: 'Profile',      desc: 'Personal info & notifications' },
  { value: 'agents',       label: 'Agents',        desc: 'Manage your course agents' },
  { value: 'integrations', label: 'Integrations',  desc: 'Connect external services' },
  { value: 'billing',      label: 'Billing',       desc: 'Plans & usage' },
];

export default function Settings() {
  const [section, setSection] = useState('profile');
  const [navOpen, setNavOpen] = useState(false);

  const current = NAV_ITEMS.find(n => n.value === section)!;

  const selectSection = (val: string) => {
    setSection(val);
    setNavOpen(false);
  };

  return (
    <div className="min-h-screen bg-background">
      <AppHeader />
      <Toaster />

      {/* Overlay nav sheet */}
      <Sheet open={navOpen} onOpenChange={setNavOpen}>
        <SheetContent side="left" className="w-64 p-0 pt-14 border-r border-border shadow-panel">
          <div className="p-4">
            <p className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider px-2 mb-2">Settings</p>
            <div className="space-y-0.5">
              {NAV_ITEMS.map(item => (
                <motion.button
                  key={item.value}
                  whileHover={{ x: 2 }}
                  transition={{ duration: 0.12 }}
                  onClick={() => selectSection(item.value)}
                  className={cn(
                    'w-full flex items-center justify-between px-3 py-2.5 rounded-xl text-left transition-all',
                    section === item.value
                      ? 'bg-secondary border border-border shadow-elevation-sm'
                      : 'text-muted-foreground hover:text-foreground hover:bg-secondary/50'
                  )}
                >
                  <div>
                    <p className={cn('text-xs', section === item.value ? 'font-medium' : '')}>{item.label}</p>
                    <p className="text-[11px] text-muted-foreground mt-0.5">{item.desc}</p>
                  </div>
                  {section === item.value && <ChevronRight className="h-3.5 w-3.5 text-muted-foreground shrink-0" />}
                </motion.button>
              ))}
            </div>
          </div>
        </SheetContent>
      </Sheet>

      <main className="pt-12">
        <div className="max-w-2xl mx-auto px-6 py-10">
          {/* Page header with nav trigger */}
          <motion.div
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.3 }}
            className="flex items-center gap-3 mb-8"
          >
            <Button
              variant="outline"
              size="sm"
              className="h-8 gap-2 text-xs shadow-elevation-sm shrink-0"
              onClick={() => setNavOpen(true)}
            >
              <Menu className="h-3.5 w-3.5" />
              <span className="hidden sm:inline">Navigation</span>
            </Button>
            <div className="min-w-0">
              <h1 className="text-xl font-semibold tracking-tight">{current.label}</h1>
              <p className="text-xs text-muted-foreground mt-0.5">{current.desc}</p>
            </div>
          </motion.div>

          {/* Full-width content — never squished */}
          <AnimatePresence mode="wait">
            <motion.div
              key={section}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
              transition={{ duration: 0.22 }}
            >
              {section === 'profile'      && <ProfileSettings />}
              {section === 'agents'       && <AgentsSettings />}
              {section === 'integrations' && <IntegrationsSettings />}
              {section === 'billing'      && <BillingSettings />}
            </motion.div>
          </AnimatePresence>
        </div>
      </main>
    </div>
  );
}

