import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Briefcase, Plus, Trash2, Pin, Search, BookOpen, Brain,
  FileText, StickyNote, Star, Clock,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import AppHeader from '@/components/layout/AppHeader';
import { cn } from '@/lib/utils';
import { Toaster } from '@/components/ui/sonner';
import { toast } from 'sonner';
import { formatDistanceToNow } from 'date-fns';

type NoteColor = 'default' | 'yellow' | 'blue' | 'green' | 'pink';

interface Note {
  id: string;
  title: string;
  content: string;
  subject: string;
  pinned: boolean;
  starred: boolean;
  color: NoteColor;
  createdAt: Date;
}

const COLOR_MAP: Record<NoteColor, string> = {
  default: 'bg-card border-border',
  yellow:  'bg-card border-border',
  blue:    'bg-card border-border',
  green:   'bg-card border-border',
  pink:    'bg-card border-border',
};

const COLOR_ACCENT: Record<NoteColor, string> = {
  default: 'bg-secondary',
  yellow:  'bg-secondary',
  blue:    'bg-secondary',
  green:   'bg-secondary',
  pink:    'bg-secondary',
};

const INITIAL_NOTES: Note[] = [
  {
    id: '1', title: 'Krebs Cycle Summary', subject: 'Biology',
    content: 'Step 1: Acetyl-CoA + Oxaloacetate → Citrate\nStep 2: Citrate → Isocitrate (no energy)\nStep 3: Isocitrate → α-KG + CO₂ + NADH\nStep 4: α-KG → Succinyl-CoA + CO₂ + NADH\nStep 5: → Succinate + GTP\nStep 6: → Fumarate + FADH₂\nStep 7: → Malate\nStep 8: → Oxaloacetate + NADH\n\nPer cycle: 3 NADH, 1 FADH₂, 1 ATP, 2 CO₂',
    pinned: true, starred: true, color: 'default', createdAt: new Date(Date.now() - 1000 * 60 * 30),
  },
  {
    id: '2', title: 'Chain Rule Reminder', subject: 'Mathematics',
    content: 'If y = f(g(x)), then dy/dx = f\'(g(x)) · g\'(x)\n\nExample: y = sin(x²)\n• Outer: cos(u)\n• Inner: 2x\n• Result: cos(x²) · 2x\n\nAlways work OUTSIDE → IN',
    pinned: true, starred: false, color: 'default', createdAt: new Date(Date.now() - 1000 * 60 * 60 * 2),
  },
  {
    id: '3', title: 'MAIN Acronym — WWI', subject: 'History',
    content: 'M — Militarism (arms race, naval competition)\nA — Alliances (Triple Alliance vs Triple Entente)\nI — Imperialism (colonial competition, Morocco Crisis)\nN — Nationalism (Pan-Slavism, Black Hand, Serbia)\n\nSarajevo = spark, not cause',
    pinned: false, starred: false, color: 'default', createdAt: new Date(Date.now() - 1000 * 60 * 60 * 24),
  },
  {
    id: '4', title: 'Big-O Quick Reference', subject: 'Computer Science',
    content: 'O(1) — constant: array access\nO(log n) — binary search\nO(n) — linear: single loop\nO(n log n) — mergesort, heapsort\nO(n²) — bubble/insertion sort\nO(2ⁿ) — recursive fib (naive)\n\nAlways aim for O(n log n) or better',
    pinned: false, starred: true, color: 'default', createdAt: new Date(Date.now() - 1000 * 60 * 60 * 48),
  },
];

const SUBJECTS = ['All', 'Biology', 'Mathematics', 'History', 'Computer Science'];

function NoteCard({ note, onDelete, onTogglePin, onToggleStar }: {
  note: Note;
  onDelete: () => void;
  onTogglePin: () => void;
  onToggleStar: () => void;
}) {
  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.96 }}
      transition={{ duration: 0.3, ease: [0.22, 1, 0.36, 1] }}
      className={cn('border rounded-2xl p-4 shadow-elevation-sm hover:shadow-elevation-md transition-all group flex flex-col', COLOR_MAP[note.color])}
    >
      {/* Subject tag */}
      <div className="flex items-center justify-between mb-2">
        <span className={cn('text-[10px] px-2 py-0.5 rounded-full border border-border font-medium text-muted-foreground', COLOR_ACCENT[note.color])}>
          {note.subject}
        </span>
        <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <button onClick={onToggleStar} className={cn('p-1 rounded-lg hover:bg-secondary/60 transition-colors', note.starred ? 'text-foreground' : 'text-muted-foreground')}>
            <Star className={cn('h-3 w-3', note.starred && 'fill-current')} />
          </button>
          <button onClick={onTogglePin} className={cn('p-1 rounded-lg hover:bg-secondary/60 transition-colors', note.pinned ? 'text-foreground' : 'text-muted-foreground')}>
            <Pin className="h-3 w-3" />
          </button>
          <button onClick={onDelete} className="p-1 rounded-lg hover:bg-secondary/60 transition-colors text-muted-foreground hover:text-destructive">
            <Trash2 className="h-3 w-3" />
          </button>
        </div>
      </div>

      {/* Title */}
      <p className="text-[13px] font-semibold mb-2 leading-snug">{note.title}</p>

      {/* Content preview */}
      <p className="text-[11px] text-muted-foreground leading-relaxed flex-1 line-clamp-5 whitespace-pre-line">
        {note.content}
      </p>

      {/* Footer */}
      <div className="flex items-center gap-2 mt-3 pt-3 border-t border-border/60">
        <Clock className="h-2.5 w-2.5 text-muted-foreground/50 shrink-0" />
        <span className="text-[10px] text-muted-foreground/50 flex-1">
          {formatDistanceToNow(note.createdAt, { addSuffix: true })}
        </span>
        {note.pinned && <Pin className="h-2.5 w-2.5 text-foreground/40" />}
        {note.starred && <Star className="h-2.5 w-2.5 text-foreground/40 fill-current" />}
      </div>
    </motion.div>
  );
}

const TOOLS = [
  { icon: StickyNote, label: 'Quick note', desc: 'Capture an idea fast' },
  { icon: FileText,   label: 'Study guide', desc: 'Structured topic overview' },
  { icon: Brain,      label: 'Ask agent',   desc: 'Get help from AI' },
  { icon: BookOpen,   label: 'Reading list', desc: 'Add to your queue' },
];

export default function Workspace() {
  const [notes, setNotes] = useState(INITIAL_NOTES);
  const [search, setSearch] = useState('');
  const [subject, setSubject] = useState('All');
  const [newTitle, setNewTitle] = useState('');
  const [showNew, setShowNew] = useState(false);

  const filtered = notes.filter(n => {
    const matchSubject = subject === 'All' || n.subject === subject;
    const matchSearch = !search || n.title.toLowerCase().includes(search.toLowerCase()) || n.content.toLowerCase().includes(search.toLowerCase());
    return matchSubject && matchSearch;
  });

  const pinned = filtered.filter(n => n.pinned);
  const rest   = filtered.filter(n => !n.pinned);

  const addNote = () => {
    if (!newTitle.trim()) return;
    const note: Note = {
      id: Date.now().toString(),
      title: newTitle.trim(),
      content: '',
      subject: subject === 'All' ? 'Biology' : subject,
      pinned: false, starred: false, color: 'default',
      createdAt: new Date(),
    };
    setNotes(prev => [note, ...prev]);
    setNewTitle('');
    setShowNew(false);
    toast('Note created');
  };

  const togglePin  = (id: string) => setNotes(prev => prev.map(n => n.id === id ? { ...n, pinned: !n.pinned } : n));
  const toggleStar = (id: string) => setNotes(prev => prev.map(n => n.id === id ? { ...n, starred: !n.starred } : n));
  const deleteNote = (id: string) => { setNotes(prev => prev.filter(n => n.id !== id)); toast('Note deleted'); };

  return (
    <div className="min-h-screen bg-background">
      <AppHeader />
      <Toaster />
      <main className="pt-12">
        {/* Header */}
        <div className="border-b border-border px-6 py-10">
          <div className="max-w-5xl mx-auto">
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }}>
              <p className="text-[11px] text-muted-foreground/50 uppercase tracking-widest font-medium mb-1">Workspace</p>
              <h1 className="text-2xl font-semibold tracking-tight mb-5">Your study space</h1>

              {/* Tools row */}
              <div className="flex flex-wrap gap-2 mb-5">
                {TOOLS.map(({ icon: Icon, label, desc }) => (
                  <button
                    key={label}
                    onClick={() => { if (label === 'Quick note') setShowNew(true); else toast(`${label} — coming soon`); }}
                    className="flex items-center gap-2 px-3 py-2 rounded-xl border border-border bg-card hover:border-foreground/20 hover:bg-secondary/40 transition-all shadow-elevation-sm text-left group"
                  >
                    <Icon className="h-3.5 w-3.5 text-muted-foreground group-hover:text-foreground transition-colors shrink-0" strokeWidth={1.5} />
                    <div>
                      <p className="text-[12px] font-medium leading-none">{label}</p>
                      <p className="text-[10px] text-muted-foreground mt-0.5">{desc}</p>
                    </div>
                  </button>
                ))}
              </div>

              {/* Search + filter */}
              <div className="flex items-center gap-2 flex-wrap">
                <div className="relative flex-1 min-w-[180px] max-w-xs">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
                  <Input
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                    placeholder="Search notes…"
                    className="pl-9 h-9 text-sm shadow-elevation-sm"
                  />
                </div>
                <div className="flex items-center gap-1 flex-wrap">
                  {SUBJECTS.map(s => (
                    <button
                      key={s}
                      onClick={() => setSubject(s)}
                      className={cn(
                        'px-3 py-1.5 rounded-lg text-[12px] transition-all font-medium',
                        subject === s
                          ? 'bg-secondary border border-border text-foreground shadow-elevation-sm'
                          : 'text-muted-foreground hover:text-foreground hover:bg-secondary/60'
                      )}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            </motion.div>
          </div>
        </div>

        <div className="max-w-5xl mx-auto px-6 py-8 space-y-8">

          {/* New note form */}
          <AnimatePresence>
            {showNew && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                transition={{ duration: 0.22 }}
                className="overflow-hidden"
              >
                <div className="border border-border rounded-2xl p-4 bg-card shadow-elevation-md">
                  <p className="text-[12px] font-medium text-muted-foreground mb-3">New note</p>
                  <div className="flex gap-2">
                    <Input
                      autoFocus
                      value={newTitle}
                      onChange={e => setNewTitle(e.target.value)}
                      onKeyDown={e => e.key === 'Enter' && addNote()}
                      placeholder="Note title…"
                      className="h-9 text-sm shadow-elevation-sm flex-1"
                    />
                    <Button size="sm" className="h-9 text-xs px-4 shadow-elevation-sm" onClick={addNote}>Create</Button>
                    <Button variant="ghost" size="sm" className="h-9 text-xs" onClick={() => setShowNew(false)}>Cancel</Button>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Pinned */}
          {pinned.length > 0 && (
            <section>
              <div className="flex items-center gap-2 mb-3">
                <Pin className="h-3 w-3 text-muted-foreground" />
                <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wider">Pinned</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                <AnimatePresence>
                  {pinned.map(n => (
                    <NoteCard key={n.id} note={n} onDelete={() => deleteNote(n.id)} onTogglePin={() => togglePin(n.id)} onToggleStar={() => toggleStar(n.id)} />
                  ))}
                </AnimatePresence>
              </div>
            </section>
          )}

          {/* All notes */}
          {rest.length > 0 && (
            <section>
              {pinned.length > 0 && (
                <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wider mb-3">All notes</p>
              )}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                <AnimatePresence>
                  {rest.map(n => (
                    <NoteCard key={n.id} note={n} onDelete={() => deleteNote(n.id)} onTogglePin={() => togglePin(n.id)} onToggleStar={() => toggleStar(n.id)} />
                  ))}
                </AnimatePresence>
              </div>
            </section>
          )}

          {filtered.length === 0 && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="border border-dashed border-border/70 rounded-2xl p-12 text-center">
              <Briefcase className="h-8 w-8 text-muted-foreground/30 mx-auto mb-3" strokeWidth={1} />
              <p className="text-sm text-muted-foreground">No notes found</p>
              <Button variant="outline" size="sm" className="mt-4 h-8 text-xs shadow-elevation-sm" onClick={() => setShowNew(true)}>
                <Plus className="h-3 w-3 mr-1.5" /> Create one
              </Button>
            </motion.div>
          )}
        </div>
      </main>
    </div>
  );
}

