import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
  BookOpen, Brain, ArrowRight, Search, Star,
  Clock, CheckCircle2, Circle, Bookmark, TrendingUp,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import AppHeader from '@/components/layout/AppHeader';
import { mockAgents } from '@/lib/mock-data';
import { cn } from '@/lib/utils';

const SUBJECTS = [
  { name: 'Biology', topics: ['Cell Division', 'Krebs Cycle', 'Genetics', 'Evolution'], progress: 72, color: 'text-foreground' },
  { name: 'Mathematics', topics: ['Chain Rule', 'Integration', 'Series', 'Limits'], progress: 58, color: 'text-foreground' },
  { name: 'History', topics: ['WWI Causes', 'Cold War', 'Colonialism', 'Renaissance'], progress: 41, color: 'text-foreground' },
  { name: 'Computer Science', topics: ['Recursion', 'Sorting Algorithms', 'Data Structures', 'Big-O'], progress: 85, color: 'text-foreground' },
];

const READING_LIST = [
  { title: 'Understanding Mitosis vs Meiosis', subject: 'Biology', estimated: '12 min', done: true },
  { title: 'L\'Hôpital\'s Rule Explained Simply', subject: 'Mathematics', estimated: '8 min', done: true },
  { title: 'Why the Allies Won World War II', subject: 'History', estimated: '15 min', done: false },
  { title: 'Dynamic Programming Patterns', subject: 'Computer Science', estimated: '20 min', done: false },
  { title: 'DNA Replication Step by Step', subject: 'Biology', estimated: '10 min', done: false },
];

const fadeUp = { initial: { opacity: 0, y: 14 }, animate: { opacity: 1, y: 0 } };

export default function LearningHub() {
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [savedIds, setSavedIds] = useState<number[]>([1]);

  const filtered = SUBJECTS.filter(s => s.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="min-h-screen bg-background">
      <AppHeader />
      <main className="pt-12">
        {/* Header */}
        <div className="border-b border-border px-6 py-10">
          <div className="max-w-5xl mx-auto">
            <motion.div {...fadeUp} transition={{ duration: 0.4 }}>
              <p className="text-[11px] text-muted-foreground/50 uppercase tracking-widest font-medium mb-1">Learning Hub</p>
              <h1 className="text-2xl font-semibold tracking-tight mb-6">Your study library</h1>
              <div className="flex items-center gap-3">
                <div className="relative flex-1 max-w-sm">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
                  <Input
                    value={search} onChange={e => setSearch(e.target.value)}
                    placeholder="Search subjects or topics…"
                    className="pl-9 h-9 text-sm shadow-elevation-sm"
                  />
                </div>
              </div>
            </motion.div>
          </div>
        </div>

        <div className="max-w-5xl mx-auto px-6 py-10 space-y-12">

          {/* Subject progress */}
          <section>
            <div className="flex items-center justify-between mb-5">
              <div>
                <h2 className="text-[13px] font-medium">Subjects</h2>
                <p className="text-[12px] text-muted-foreground mt-0.5">Track mastery across your courses</p>
              </div>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {filtered.map((subject, i) => {
                const agent = mockAgents.find(a => a.subject === subject.name);
                return (
                  <motion.div
                    key={subject.name}
                    initial={{ opacity: 0, y: 14 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.06, duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
                    className="border border-border rounded-2xl p-5 bg-card shadow-elevation-sm hover:shadow-elevation-md hover:border-foreground/20 transition-all cursor-pointer group"
                    onClick={() => navigate('/chat')}
                  >
                    <div className="flex items-start justify-between mb-4">
                      <div className="w-9 h-9 rounded-xl bg-secondary border border-border flex items-center justify-center shadow-elevation-sm">
                        <BookOpen className="h-4 w-4 text-muted-foreground" strokeWidth={1.5} />
                      </div>
                      <span className="text-xs text-muted-foreground font-medium">{subject.progress}%</span>
                    </div>
                    <p className="text-[13px] font-medium mb-1">{subject.name}</p>
                    <div className="flex flex-wrap gap-1 mb-4">
                      {subject.topics.map(t => (
                        <span key={t} className="text-[10px] px-1.5 py-0.5 rounded-full border border-border bg-secondary text-muted-foreground">{t}</span>
                      ))}
                    </div>
                    {/* Progress bar */}
                    <div className="h-1.5 rounded-full bg-secondary border border-border overflow-hidden">
                      <motion.div
                        className="h-full rounded-full bg-foreground"
                        initial={{ width: 0 }}
                        animate={{ width: `${subject.progress}%` }}
                        transition={{ duration: 0.7, delay: 0.2 + i * 0.06, ease: [0.22, 1, 0.36, 1] }}
                      />
                    </div>
                    <div className="flex items-center justify-between mt-3">
                      <span className="text-[11px] text-muted-foreground">
                        {agent ? `${agent.conversations} sessions` : '0 sessions'}
                      </span>
                      <div className="flex items-center gap-1 text-[11px] text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity">
                        Study now <ArrowRight className="h-3 w-3" />
                      </div>
                    </div>
                  </motion.div>
                );
              })}
            </div>
          </section>

          {/* Reading list */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <div>
                <h2 className="text-[13px] font-medium">Reading list</h2>
                <p className="text-[12px] text-muted-foreground mt-0.5">Topics your agents recommend reviewing</p>
              </div>
              <div className="flex items-center gap-1.5 text-[11px] text-muted-foreground">
                <TrendingUp className="h-3.5 w-3.5" />
                {READING_LIST.filter(r => r.done).length}/{READING_LIST.length} done
              </div>
            </div>
            <div className="divide-y divide-border/50 border border-border rounded-2xl bg-card shadow-elevation-sm overflow-hidden">
              {READING_LIST.map((item, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.15 + i * 0.05, duration: 0.35 }}
                  className="flex items-center gap-4 px-5 py-3.5 hover:bg-secondary/30 transition-colors cursor-pointer group"
                >
                  <button
                    className="shrink-0"
                    onClick={e => e.stopPropagation()}
                  >
                    {item.done
                      ? <CheckCircle2 className="h-4 w-4 text-foreground/50" strokeWidth={1.5} />
                      : <Circle className="h-4 w-4 text-muted-foreground/40" strokeWidth={1.5} />
                    }
                  </button>
                  <div className="flex-1 min-w-0">
                    <p className={cn('text-[13px] font-medium truncate', item.done && 'line-through text-muted-foreground')}>{item.title}</p>
                    <p className="text-[11px] text-muted-foreground mt-0.5">{item.subject} · {item.estimated} read</p>
                  </div>
                  <div className="flex items-center gap-2 shrink-0">
                    <button
                      onClick={e => { e.stopPropagation(); setSavedIds(prev => prev.includes(i) ? prev.filter(x => x !== i) : [...prev, i]); }}
                      className="text-muted-foreground hover:text-foreground transition-colors"
                    >
                      <Bookmark className={cn('h-3.5 w-3.5', savedIds.includes(i) && 'fill-current')} />
                    </button>
                    <button
                      onClick={() => navigate('/chat')}
                      className="opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <div className="flex items-center gap-1 text-[11px] text-muted-foreground">
                        <Brain className="h-3.5 w-3.5" strokeWidth={1.5} />
                        Ask agent
                      </div>
                    </button>
                  </div>
                </motion.div>
              ))}
            </div>
          </section>

          {/* Quick study */}
          <section>
            <h2 className="text-[13px] font-medium mb-4">Jump into a session</h2>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2.5">
              {mockAgents.map((agent, i) => (
                <motion.button
                  key={agent.id}
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.3 + i * 0.05, duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
                  onClick={() => navigate('/chat')}
                  className="flex flex-col items-center gap-2 p-4 rounded-2xl border border-border bg-card hover:border-foreground/20 hover:bg-secondary/30 transition-all shadow-elevation-sm"
                >
                  <div className="w-9 h-9 rounded-xl bg-secondary border border-border flex items-center justify-center">
                    <Brain className="h-4 w-4 text-muted-foreground" strokeWidth={1.5} />
                  </div>
                  <p className="text-[12px] font-medium text-center leading-tight">{agent.subject}</p>
                  <div className="flex items-center gap-1 text-[10px] text-muted-foreground">
                    <Clock className="h-2.5 w-2.5" />
                    <span>{agent.conversations} sessions</span>
                  </div>
                </motion.button>
              ))}
            </div>
          </section>
        </div>
      </main>
    </div>
  );
}

