import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Plus, Search, X, Brain, Clock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { mockConversations } from '@/lib/mock-data';
import { formatDistanceToNow } from 'date-fns';
import { cn } from '@/lib/utils';

interface Props {
  onClose: () => void;
}

export default function ConversationSidebar({ onClose }: Props) {
  const navigate = useNavigate();
  const { id } = useParams();
  const [search, setSearch] = useState('');

  const filtered = mockConversations.filter(c =>
    c.title.toLowerCase().includes(search.toLowerCase()) ||
    (c.agentName ?? '').toLowerCase().includes(search.toLowerCase())
  );

  const groups = [
    { label: 'Today',   items: filtered.filter(c => Date.now() - c.timestamp.getTime() < 86_400_000) },
    { label: 'Earlier', items: filtered.filter(c => Date.now() - c.timestamp.getTime() >= 86_400_000) },
  ];

  const handleSelect = (convId: string) => {
    navigate(`/chat/${convId}`);
    onClose();
  };

  return (
    <motion.div
      initial={{ x: -288 }}
      animate={{ x: 0 }}
      exit={{ x: -288 }}
      transition={{ type: 'spring', stiffness: 340, damping: 34 }}
      className="flex flex-col h-full bg-background border-r border-border w-72 shadow-panel"
    >
      {/* Header */}
      <div className="flex items-center justify-between px-3 py-3 border-b border-border">
        <span className="text-[11px] font-medium text-muted-foreground uppercase tracking-widest px-1">Conversations</span>
        <Button variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-foreground" onClick={onClose}>
          <X className="h-3.5 w-3.5" />
        </Button>
      </div>

      {/* New chat */}
      <div className="px-3 pt-3 pb-2">
        <Button
          variant="outline" size="sm"
          className="w-full h-8 text-xs justify-start gap-2 shadow-elevation-sm text-muted-foreground hover:text-foreground"
          onClick={() => { navigate('/chat'); onClose(); }}
        >
          <Plus className="h-3.5 w-3.5" /> New conversation
        </Button>
      </div>

      {/* Search */}
      <div className="px-3 pb-2">
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3 w-3 text-muted-foreground/50" />
          <input
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search…"
            className="w-full h-7 rounded-lg bg-secondary/40 border border-border pl-7 pr-3 text-[12px] focus:outline-none focus:border-foreground/25 transition-colors placeholder:text-muted-foreground/40"
          />
        </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto py-1 px-1.5">
        {groups.map(group => group.items.length > 0 && (
          <div key={group.label} className="mb-2">
            <p className="px-3 py-1.5 text-[10px] font-medium text-muted-foreground/50 uppercase tracking-widest">{group.label}</p>
            {group.items.map(conv => (
              <motion.button
                key={conv.id}
                onClick={() => handleSelect(conv.id)}
                whileHover={{ x: 2 }}
                transition={{ duration: 0.12 }}
                className={cn(
                  'w-full text-left px-3 py-2.5 rounded-xl transition-all flex items-start gap-2.5 mb-0.5',
                  id === conv.id
                    ? 'bg-secondary border border-border shadow-elevation-sm'
                    : 'hover:bg-secondary/50 text-muted-foreground hover:text-foreground'
                )}
              >
                <div className={cn(
                  'w-5 h-5 rounded-md border border-border flex items-center justify-center shrink-0 mt-0.5',
                  id === conv.id ? 'bg-secondary' : 'bg-secondary/40'
                )}>
                  <Brain className="h-2.5 w-2.5 text-muted-foreground" strokeWidth={1.5} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className={cn('text-[12px] truncate', id === conv.id ? 'font-medium text-foreground' : '')}>{conv.title}</p>
                  {conv.agentName && (
                    <p className="text-[10.5px] text-muted-foreground/60 truncate mt-0.5">{conv.agentName}</p>
                  )}
                </div>
              </motion.button>
            ))}
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="px-4 py-8 text-center">
            <p className="text-[12px] text-muted-foreground">No conversations found</p>
          </div>
        )}
      </div>

      {/* Footer */}
      <div className="border-t border-border px-4 py-3">
        <div className="flex items-center gap-2.5">
          <div className="w-6 h-6 rounded-full bg-secondary border border-border flex items-center justify-center text-[10px] font-medium shrink-0">
            U
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-[12px] font-medium">Student</p>
            <p className="text-[10.5px] text-muted-foreground/60">Free plan · {mockConversations.length} conversations</p>
          </div>
          <Clock className="h-3 w-3 text-muted-foreground/30 shrink-0" />
        </div>
      </div>
    </motion.div>
  );
}

