/* Custom scrollbar */
::-webkit-scrollbar { width: 4px; height: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: hsl(var(--border)); border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: hsl(var(--muted-foreground)); }

/* Streaming cursor */
@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}
.streaming-cursor::after {
  content: '▋';
  animation: blink 1s infinite;
  margin-left: 1px;
}

/* Typing dots */
@keyframes typingBounce {
  0%, 60%, 100% { transform: translateY(0); }
  30% { transform: translateY(-5px); }
}
.typing-dot {
  animation: typingBounce 1.2s infinite;
}

/* Shimmer for loading */
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
.shimmer {
  background: linear-gradient(90deg, hsl(var(--muted)) 25%, hsl(var(--secondary)) 50%, hsl(var(--muted)) 75%);
  background-size: 200% auto;
  animation: shimmer 1.5s infinite linear;
}

/* Bob float for student symbols */
@keyframes bobFloat {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-14px); }
}

/* Globe spin */
@keyframes globeSpin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

/* Page fade */
@keyframes fadeSlideUp {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: translateY(0); }
}
.animate-fade-slide-up {
  animation: fadeSlideUp 0.4s ease-out both;
}

/* Brain edge glow — waves */
@keyframes brainGlowWave {
  0%   { filter: drop-shadow(0 0 0px hsl(270 80% 65% / 0)); }
  25%  { filter: drop-shadow(0 0 5px hsl(270 80% 70% / 0.55)) drop-shadow(0 0 10px hsl(270 60% 55% / 0.25)); }
  50%  { filter: drop-shadow(0 0 8px hsl(270 80% 65% / 0.75)) drop-shadow(0 0 18px hsl(270 55% 50% / 0.35)); }
  75%  { filter: drop-shadow(0 0 5px hsl(270 80% 70% / 0.55)) drop-shadow(0 0 10px hsl(270 60% 55% / 0.25)); }
  100% { filter: drop-shadow(0 0 0px hsl(270 80% 65% / 0)); }
}
.brain-glow {
  animation: brainGlowWave 2.8s ease-in-out infinite;
}

/* Verb card icon animations */
@keyframes iconPulse {
  0%, 100% { transform: scale(1); opacity: 0.9; }
  50% { transform: scale(1.15); opacity: 1; }
}
@keyframes iconBounce {
  0%, 100% { transform: translateY(0); }
  40% { transform: translateY(-4px); }
}
@keyframes iconWiggle {
  0%, 100% { transform: rotate(0deg); }
  20% { transform: rotate(-8deg); }
  60% { transform: rotate(8deg); }
}
@keyframes iconSpin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}
@keyframes iconZoom {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.2); }
}
@keyframes iconExpand {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.18); opacity: 0.85; }
}
.icon-pulse { animation: iconPulse 2.2s ease-in-out infinite; }
.icon-bounce { animation: iconBounce 1.8s ease-in-out infinite; }
.icon-wiggle { animation: iconWiggle 2s ease-in-out infinite; }
.icon-spin { animation: iconSpin 3s linear infinite; }
.icon-zoom { animation: iconZoom 2.5s ease-in-out infinite; }
.icon-expand { animation: iconExpand 2s ease-in-out infinite; }

