const RESPONSES = [
  "Great question! Let me break this down step by step.\n\n**Key Concept:**\nThe fundamental principle here is rooted in how information flows through interconnected systems.\n\n- Start with the outermost layer\n- Work inward, applying each transformation\n- Combine results at each step\n\nThis approach ensures you never miss a step and can always trace your reasoning back.",
  "I've analyzed your question carefully. Here's how I'd approach this:\n\n**Step 1 — Identify the structure**\nLook at what you're working with and map out the components.\n\n**Step 2 — Apply the principle**\nUse the core rule, making sure to handle edge cases.\n\n**Step 3 — Verify your answer**\nCheck by working backwards from your result.\n\nDoes this approach make sense? I can go deeper on any of these steps.",
  "Excellent! This is a classic topic that trips up a lot of students. Here's the intuition:\n\nImagine you're peeling back layers 🧅 — each layer has its own rule, and you apply them sequentially from outside in.\n\n```python\n# Here's a concrete example:\ndef apply_rules(x):\n    # Outer layer first\n    outer = transform_outer(x)\n    # Then inner\n    inner = transform_inner(outer)\n    return inner\n```\n\nThe key insight: **never skip a layer**, even if it seems trivial.",
];

/* Detect verb type from user message */
function detectVerb(text: string): VerbType {
  const t = text.trim().toLowerCase();
  if (/^(search|find|look up|lookup|google|show me results|search for)/i.test(t)) return 'searching';
  if (/create\s+(a\s+)?project|new project/i.test(t)) return 'creating-project';
  if (/create\s+(a\s+)?(file|note|document|doc)|new\s+(file|note|document)/i.test(t)) return 'creating-file';
  if (/^(read|read through|summarize|analyse|analyze|go through|review)/i.test(t)) return 'reading';
  return 'thinking';
}

/* Detect if message is a search query */
function isSearchQuery(text: string) {
  return /^(search|find|look up|lookup|show me|what is|define|who is)/i.test(text.trim());
}

/* Generate instant search results */
function buildSearchResponse(query: string): string {
  const term = query.replace(/^(search for|search|find|look up|lookup|show me|what is|define|who is)\s*/i, '').trim();
  return `**Search results for "${term}"**\n\nHere's what I found across your study materials:\n\n📚 **Learning Hub**\n- Topics matching "${term}" in Biology, Mathematics, and Computer Science\n- 3 related notes in your Workspace\n\n💬 **Recent conversations**\n- "Explain the Krebs cycle" — mentions ${term}\n- "Derivatives of composite functions" — related concepts\n\n📖 **Suggested reading**\n- ${term}: A complete overview\n- Common misconceptions about ${term}\n- Practice questions on ${term}\n\nWould you like me to explain any of these topics in detail?`;
}

