/* ─── Pattern Avatar ─── */
function PatternAvatar({ size = 32, seed = 42 }: { size?: number; seed?: number }) {
  const cells = 7, cellSize = size / cells, half = Math.ceil(cells / 2);
  const grid: boolean[][] = Array.from({ length: cells }, (_, r) =>
    Array.from({ length: half }, (_, c) => ((seed * (r * 13 + c * 7 + 3)) % 17) > 6)
  );
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ borderRadius: '50%', display: 'block' }}>
      <rect width={size} height={size} fill="hsl(270 60% 18%)" />
      {grid.map((row, r) => row.map((on, c) => {
        if (!on) return null;
        const m = cells - 1 - c;
        const rs = c === m ? [{ x: c * cellSize, y: r * cellSize }] : [{ x: c * cellSize, y: r * cellSize }, { x: m * cellSize, y: r * cellSize }];
        return rs.map((rect, i) => (
          <rect key={`${r}-${c}-${i}`} x={rect.x} y={rect.y} width={cellSize} height={cellSize}
            fill="hsl(270 80% 65%)" opacity={0.85 + (((r * 3 + c * 5) % 4) * 0.04)} />
        ));
      }))}
      {grid.map((row, r) => row.map((on, c) => {
        if (!on) return null;
        const m = cells - 1 - c;
        const ps = c === m
          ? [{ x: c * cellSize + cellSize * 0.3, y: r * cellSize + cellSize * 0.3 }]
          : [{ x: c * cellSize + cellSize * 0.3, y: r * cellSize + cellSize * 0.3 }, { x: m * cellSize + cellSize * 0.3, y: r * cellSize + cellSize * 0.3 }];
        return ps.map((p, i) => (
          <rect key={`d-${r}-${c}-${i}`} x={p.x} y={p.y} width={cellSize * 0.35} height={cellSize * 0.35}
            fill="hsl(280 90% 80%)" opacity={0.5} />
        ));
      }))}
    </svg>
  );
}

